resetRadioOptions();
detectFullHouse([1,2,3,4,5]);
assert.isTrue(scoreInputs[2].disabled);
assert.isFalse(scoreInputs[5].disabled);
assert.strictEqual(scoreInputs[5].value, "0");
assert.strictEqual(scoreSpans[5].innerText, ", score = 0");

// Temporarily modifies Math.random to guarantee full house.
const origMathRandom = Math.random
const myMathRandom = (() => {
  let i = 0;
  const values = [0, 0, 0, 1 / 6 + 0.000001, 1 / 6 + 0.000001];
  return () => values[i++ % 5];
})();

Math.random = myMathRandom;
try {
  rollDiceBtn.click();
} finally {
  Math.random = origMathRandom;
}

assert.isFalse(scoreInputs[2].disabled);
assert.strictEqual(scoreInputs[2].value, "25");
assert.strictEqual(scoreSpans[2].innerText, ", score = 25");
